function getRegion(comuna){
  const key=comuna.toUpperCase().trim().normalize("NFD").replace(/[\u0300-\u036f]/g,"");
  return COMUNAS[key]||"";
}

function getProvincia(comuna,region){
  const key=comuna.toUpperCase().trim().normalize("NFD").replace(/[\u0300-\u036f]/g,"");
  if(region==="METROPOLITANA"&&PROVINCIAS["METROPOLITANA"][key]) return PROVINCIAS["METROPOLITANA"][key];
  return "";
}

const fmtMiles=(v)=>{
  if(v===undefined||v===null)return "";
  const s=String(v).replace(/\./g,"");
  const parts=s.split(",");
  const ent=parts[0].replace(/\D/g,"");
  if(!ent)return "";
  const fmt=ent.replace(/\B(?=(\d{3})+(?!\d))/g,".");
  return parts.length>1?fmt+","+parts[1]:fmt;
};

// Estilo tipografico unico del informe: misma fuente, tamano, interlineado, justificado
const TXT={fontFamily:FONT,fontSize:13.5,lineHeight:1.85,color:"#2b2b2b",textAlign:"justify",margin:"0 0 10px"};

function Lbl({c}){ return <div style={{fontSize:12,fontWeight:600,color:GRIS,marginBottom:5}}>{c}</div>; }
function Fld({label,value,onChange,placeholder,type,multi,req,warn}){
  const vacio=!String(value===undefined||value===null?"":value).trim();
  const extra=vacio&&req?{border:"2px solid #e53935",background:"#fff8f8"}:vacio&&warn?{border:"2px solid "+ORO,background:"#fffdf5"}:{};
  return <div style={{marginBottom:4}}>
    <Lbl c={label+(req?" *":"")}/>
    {multi
      ? <textarea value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder||""} rows={3} style={{...iS,resize:"vertical",...extra}}/>
      : <input type={type||"text"} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder||""} style={{...iS,...extra}}/>}
  </div>;
}
function Card({children,style}){ return <div style={{background:"#fff",borderRadius:10,padding:24,marginBottom:16,border:"1px solid #e8e8e8",boxShadow:"0 1px 4px rgba(0,0,0,0.04)",...style}}>{children}</div>; }
function G2({children,mt}){ return <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginTop:mt||0}}>{children}</div>; }
function G3({children}){ return <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:12}}>{children}</div>; }
function SecT({icon,title}){
  return <div style={{display:"flex",alignItems:"center",gap:10,margin:"28px 0 12px",borderBottom:"2px solid "+G,paddingBottom:8}}>
    <span style={{fontSize:18}}>{icon}</span>
    <h2 style={{margin:0,color:G,fontSize:16,fontFamily:FONT,fontWeight:700}}>{title}</h2>
  </div>;
}
function capTxt(s){return String(s||"").trim().toLowerCase().replace(/(^|[\s.\-("])([a-zaeiounü\u00e1\u00e9\u00ed\u00f3\u00fa\u00f1])/g,(m,p,l)=>p+l.toUpperCase());}
